SELECT sim_id, run_duration
FROM simulations
WHERE run_duration = (SELECT MAX(run_duration) FROM simulations);

SELECT code_name 
FROM simulation_codes 
WHERE version = '2.0';

SELECT MIN(value) AS min_parameter_value
FROM simulation_code_parameters
WHERE code_id = 0;

SELECT simulations.sim_id, datasets.path
FROM simulations
INNER JOIN datasets ON simulations.sim_id = datasets.sim_id;

SELECT plasma_type, value
FROM plasma_data
ORDER BY plasma_type ASC;

SELECT sim_id
FROM simulations
WHERE code_id = 1 AND run_date = '2023-05-01';

SELECT COUNT(DISTINCT user_id) AS unique_users
FROM access_logs
WHERE sim_id = 'SPECIFIC_SIM_ID';
